$devices = Get-PnpDevice -Class Net -ErrorAction SilentlyContinue | Where-Object { $_.FriendlyName -match 'Wi-Fi|WiFi|Wireless|WLAN|802\.11' -and $_.Status -ne 'OK' }; if ($devices) { foreach($d in $devices) { Write-Host '  Bandoma atnaujinti:' $d.FriendlyName; pnputil /enable-device $d.InstanceId 2>$null }; Write-Host '  [OK] Irenginiai ijungti.' } else { Write-Host '  [i] Visi WiFi irenginiai jau OK arba nerasti.' }
